-- Remove school_name unique constraint (now only school_code is unique)
SET @idx_exists = (SELECT COUNT(*) FROM INFORMATION_SCHEMA.STATISTICS WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'sys_school' AND INDEX_NAME = 'uk_sys_school_name');
SET @drop_sql = IF(@idx_exists > 0, 'ALTER TABLE sys_school DROP INDEX uk_sys_school_name', 'SELECT 1');
PREPARE stmt FROM @drop_sql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;
